#include <iostream>
#include <string>
#include <sys/socket.h>
#include <arpa/inet.h>
#include <unistd.h>
#include <netdb.h>
#include <stdlib.h>
#include <stdio.h>
#include <math.h>

using namespace std;

const int MAX_PLAYERS = 100; // Maximum number of players in the game
const int BUFFER_SIZE = 4096; // Size of the buffer for receiving packets
const int PORT = 27910; // Port number for the server

// Structure to hold player information
struct Player {
    int id;
    float x, y, z;
    bool isShooting;
};

// Array of players in the game
Player players[MAX_PLAYERS];

// Socket file descriptor for receiving packets
int sockfd;

// Server loop function to handle incoming packets
void serverLoop() {
    while (1) {
        // Receive a packet from a client
        char buffer[BUFFER_SIZE];
        int bytesReceived = recv(sockfd, buffer, BUFFER_SIZE, 0);
        if (bytesReceived <= 0) {
            break;
        }

        // Parse the received packet
        string packet = buffer.substr(0, bytesReceived);
        int playerId = stoi(packet.substr(0, packet.find(' ')));
        float x = stof(packet.substr(packet.find(' ') + 1));
        float y = stof(packet.substr(packet.find(' ', 2) + 1));
        float z = stof(packet.substr(packet.find(' ', 3) + 1));
        bool isShooting = packet.find("shooting") != string::npos;

        // Update the player position and shooting status
        Player *player = &players[playerId];
        player->x = x;
        player->y = y;
        player->z = z;
        player->isShooting = isShooting;

        // Broadcast the updated player information to all clients
        for (int i = 0; i < MAX_PLAYERS; ++i) {
            if (players[i].id != -1) {
                send(sockfd, "update " + to_string(player->id) + " " + to_string(player->x) + " " + to_string(player->y) + " " + to_string(player->z) + (player->isShooting ? " shooting" : "") + "\n", 0);
            }
        }
    }
}

int main() {
    // Initialize the server socket
    sockfd = socket(AF_INET, SOCK_DGRAM, 0);
    if (sockfd < 0) {
        perror("Error creating socket");
        return EXIT_FAILURE;
    }

    // Bind the socket to a specific address and port
    struct sockaddr_in servAddr;
    memset(&servAddr, 0, sizeof(servAddr));
    servAddr.sin_family = AF_INET;
    servAddr.sin_port = htons(PORT);
    inet_pton(AF_INET, "127.0.0.1", &servAddr.sin_addr);
    if (bind(sockfd, (struct sockaddr *)&servAddr, sizeof(servAddr)) < 0) {
        perror("Error binding socket");
        return EXIT_FAILURE;
    }

    // Set up the server loop function to handle incoming packets
    pthread_t thread;
    if (pthread_create(&thread, NULL, &serverLoop, NULL)) {
        perror("Error creating thread");
        return EXIT_FAILURE;
    }

    printf("Server started on port %d\n", PORT);

    // Wait for the server loop function to finish
    pthread_join(thread, NULL);

    close(sockfd);

    return EXIT_SUCCESS;
}
